/**
 * Camunda Process Test Coverage Report – Application
 *
 * Lightweight vanilla-JS single-page application that renders the coverage
 * report generated by the camunda-process-test-java module.
 *
 * Architecture
 * ─────────────
 *  • Hash-based router for deep-linkable navigation (no server required)
 *  • Sidebar: hierarchical navigation (Dashboard / Processes / Test Suites)
 *  • Main content: Dashboard | Process view | Suite view | Run view
 *  • bpmn-js (navigated viewer) for BPMN diagram rendering with coverage colours
 *
 * Data format (window.COVERAGE_DATA)
 * ────────────────────────────────────
 * {
 *   suites:     SuiteCoverageReport[]   // per-suite results
 *   coverages:  Coverage[]              // aggregated across all suites
 *   definitions: { [processId]: string } // BPMN XML per process
 * }
 *
 * SuiteCoverageReport: { id, name, runs: Run[], models: Model[], coverages: Coverage[] }
 * Run:                 { name, coverages: Coverage[] }
 * Coverage:            { processDefinitionId, completedElements, takenSequenceFlows, coverage }
 * Model:               { processDefinitionId, totalElementCount, version }
 */

(function () {
  'use strict';

  // ── Constants ────────────────────────────────────────────────────────────────

  /** Camunda brand colours */
  const COLORS = {
    blue: '#0072CE',
    green: '#26D07C',
    lightGrey: '#E6E7E8',
    midGrey: '#888B8D',
  };

  /** Coverage threshold below which a process is considered "low" coverage */
  const LOW_COVERAGE_THRESHOLD = 0.5;

  // ── Data ──────────────────────────────────────────────────────────────────────

  const data = window.COVERAGE_DATA;

  if (!data) {
    document.getElementById('content').innerHTML =
      '<div class="alert alert-danger m-3">No coverage data available. ' +
      'This page requires <code>window.COVERAGE_DATA</code> to be set.</div>';
    return;
  }

  // Ensure collections are always arrays
  const suites = data.suites || [];
  const globalCoverages = data.coverages || [];
  const definitions = data.definitions || {};

  // ── Helpers ───────────────────────────────────────────────────────────────────

  /**
   * Returns a string like "75.0%" from a decimal in [0, 1].
   * @param {number} value
   * @returns {string}
   */
  function toPercent(value) {
    return (value * 100).toFixed(1) + '%';
  }

  /**
   * Returns the Bootstrap colour class for a coverage value.
   * @param {number} value
   * @returns {string}
   */
  function coverageClass(value) {
    if (value >= 0.8) return 'coverage-high';
    if (value >= 0.5) return 'coverage-medium';
    return 'coverage-low';
  }

  /**
   * Escapes HTML special characters.
   * @param {string} str
   * @returns {string}
   */
  function escapeHtml(str) {
    return String(str)
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  /**
   * Renders a progress bar element for a given coverage value.
   * @param {number} value Coverage value in [0, 1].
   * @returns {string} HTML string.
   */
  function progressBarHtml(value) {
    const pct = (value * 100).toFixed(1);
    const cls = coverageClass(value);
    return `
      <div class="coverage-bar-wrap" title="${pct}%">
        <div class="coverage-bar ${cls}" style="width:${pct}%"></div>
      </div>`;
  }

  /**
   * Renders a coverage badge.
   * @param {number} value Coverage value in [0, 1].
   * @returns {string} HTML string.
   */
  function badgeHtml(value) {
    const cls = coverageClass(value);
    return `<span class="coverage-badge ${cls}">${toPercent(value)}</span>`;
  }

  /**
   * Looks up the aggregated coverage entry for a process.
   * @param {string} processId
   * @returns {object|undefined}
   */
  function findGlobalCoverage(processId) {
    return globalCoverages.find((c) => c.processDefinitionId === processId);
  }

  /**
   * Looks up a suite by id.
   * @param {string} suiteId
   * @returns {object|undefined}
   */
  function findSuite(suiteId) {
    return suites.find((s) => s.id === suiteId);
  }

  // ── Router ────────────────────────────────────────────────────────────────────

  /**
   * Parses the current URL hash into a route object.
   * Supported hash patterns:
   *   #/                                → { view: 'dashboard' }
   *   #/process/<processId>             → { view: 'process', processId }
   *   #/suite/<suiteId>                 → { view: 'suite', suiteId }
   *   #/suite/<suiteId>/run/<runName>   → { view: 'run', suiteId, runName }
   *
   * @returns {{ view: string, [key: string]: string }}
   */
  function parseRoute() {
    const hash = window.location.hash.replace(/^#/, '') || '/';
    const parts = hash.split('/').filter(Boolean);

    if (parts.length === 0 || parts[0] === '') {
      return { view: 'dashboard' };
    }

    switch (parts[0]) {
      case 'process':
        return { view: 'process', processId: decodeURIComponent(parts[1] || '') };
      case 'suite': {
        const suiteId = decodeURIComponent(parts[1] || '');
        if (parts[2] === 'run') {
          return { view: 'run', suiteId, runName: decodeURIComponent(parts[3] || '') };
        }
        return { view: 'suite', suiteId };
      }
      default:
        return { view: 'dashboard' };
    }
  }

  /**
   * Navigates to the given hash path.
   * @param {string} path e.g. "/process/my-process"
   */
  function navigate(path) {
    window.location.hash = '#' + path;
  }

  // ── Sidebar ───────────────────────────────────────────────────────────────────

  /**
   * Builds and renders the sidebar navigation.
   * The sidebar is rendered once; active state is updated on each route change.
   */
  function renderSidebar() {
    const container = document.getElementById('sidebar-content');
    if (!container) return;

    container.innerHTML = buildSidebarHtml();
    attachSidebarListeners();
  }

  function buildSidebarHtml() {
    let html = `
      <ul class="nav-list" role="list">
        <!-- Dashboard -->
        <li>
          <a class="nav-item nav-item-top" href="#/" data-route="dashboard">
            <i class="bi bi-house-fill me-2" aria-hidden="true"></i>Dashboard
          </a>
        </li>`;

    // ── Processes section ──────────────────────────────────────────────────
    if (globalCoverages.length > 0) {
      html += `
        <li class="nav-section-header">
          <i class="bi bi-diagram-3 me-2" aria-hidden="true"></i>Processes
        </li>`;

      const sorted = [...globalCoverages].sort((a, b) => b.coverage - a.coverage);
      for (const cov of sorted) {
        const pid = encodeURIComponent(cov.processDefinitionId);
        html += `
          <li>
            <a class="nav-item nav-item-process"
               href="#/process/${pid}"
               data-route="process"
               data-process-id="${escapeHtml(cov.processDefinitionId)}"
               title="${escapeHtml(cov.processDefinitionId)}">
              <i class="bi bi-diagram-3-fill me-2" aria-hidden="true"></i>
              <span class="nav-item-label">${escapeHtml(cov.processDefinitionId)}</span>
              ${badgeHtml(cov.coverage)}
            </a>
          </li>`;
      }
    }

    // ── Test Suites section ────────────────────────────────────────────────
    if (suites.length > 0) {
      html += `
        <li class="nav-section-header">
          <i class="bi bi-folder2 me-2" aria-hidden="true"></i>Test Suites
        </li>`;

      for (const suite of suites) {
        const sid = encodeURIComponent(suite.id);
        const collapseId = `suite-collapse-${sid.replace(/[^a-zA-Z0-9]/g, '_')}`;

        html += `
          <li class="nav-suite">
            <div class="nav-item nav-item-suite d-flex align-items-center"
                 role="button"
                 data-bs-toggle="collapse"
                 data-bs-target="#${collapseId}"
                 aria-expanded="false"
                 aria-controls="${collapseId}">
              <i class="bi bi-caret-right-fill nav-caret me-1" aria-hidden="true"></i>
              <a class="nav-suite-link flex-grow-1 text-truncate"
                 href="#/suite/${sid}"
                 data-route="suite"
                 data-suite-id="${escapeHtml(suite.id)}"
                 title="${escapeHtml(suite.name)}"
                 onclick="event.stopPropagation()">
                <i class="bi bi-folder-fill me-2" aria-hidden="true"></i>
                ${escapeHtml(suite.name)}
              </a>
            </div>
            <div class="collapse ms-3" id="${collapseId}">
              <ul class="nav-list" role="list">`;

        // Runs (test cases) inside the suite
        const runs = suite.runs || [];
        for (const run of runs) {
          const rn = encodeURIComponent(run.name);
          const runCollapseId = `run-collapse-${sid.replace(/[^a-zA-Z0-9]/g, '_')}_${rn.replace(/[^a-zA-Z0-9]/g, '_')}`;

          html += `
                <li class="nav-run">
                  <div class="nav-item nav-item-run d-flex align-items-center"
                       role="button"
                       data-bs-toggle="collapse"
                       data-bs-target="#${runCollapseId}"
                       aria-expanded="false"
                       aria-controls="${runCollapseId}">
                    <i class="bi bi-caret-right-fill nav-caret me-1" aria-hidden="true"></i>
                    <a class="nav-run-link flex-grow-1 text-truncate"
                       href="#/suite/${sid}/run/${rn}"
                       data-route="run"
                       data-suite-id="${escapeHtml(suite.id)}"
                       data-run-name="${escapeHtml(run.name)}"
                       title="${escapeHtml(run.name)}"
                       onclick="event.stopPropagation()">
                      <i class="bi bi-file-earmark-code-fill me-2" aria-hidden="true"></i>
                      <span class="nav-item-label">${escapeHtml(run.name)}</span>
                    </a>
                  </div>
                  <div class="collapse ms-3" id="${runCollapseId}">
                    <ul class="nav-list" role="list">`;

          // Processes covered by this run
          const runCoverages = run.coverages || [];
          for (const cov of runCoverages) {
            const pid = encodeURIComponent(cov.processDefinitionId);
            html += `
                      <li>
                        <a class="nav-item nav-item-process-leaf"
                           href="#/process/${pid}"
                           data-route="process"
                           data-process-id="${escapeHtml(cov.processDefinitionId)}"
                           title="${escapeHtml(cov.processDefinitionId)}">
                          <i class="bi bi-diagram-3-fill me-2" aria-hidden="true"></i>
                          <span class="nav-item-label">${escapeHtml(cov.processDefinitionId)}</span>
                          ${badgeHtml(cov.coverage)}
                        </a>
                      </li>`;
          }

          html += `
                    </ul>
                  </div>
                </li>`;
        }

        // Also show processes aggregated at the suite level
        const suiteCoverages = suite.coverages || [];
        if (suiteCoverages.length > 0 && runs.length === 0) {
          for (const cov of suiteCoverages) {
            const pid = encodeURIComponent(cov.processDefinitionId);
            html += `
              <li>
                <a class="nav-item nav-item-process-leaf"
                   href="#/process/${pid}"
                   data-route="process"
                   data-process-id="${escapeHtml(cov.processDefinitionId)}"
                   title="${escapeHtml(cov.processDefinitionId)}">
                  <i class="bi bi-diagram-3-fill me-2" aria-hidden="true"></i>
                  <span class="nav-item-label">${escapeHtml(cov.processDefinitionId)}</span>
                  ${badgeHtml(cov.coverage)}
                </a>
              </li>`;
          }
        }

        html += `
              </ul>
            </div>
          </li>`;
      }
    }

    html += '</ul>';
    return html;
  }

  function attachSidebarListeners() {
    // Update caret icon when collapse opens/closes
    document.querySelectorAll('[data-bs-toggle="collapse"]').forEach((btn) => {
      const targetId = btn.getAttribute('data-bs-target');
      const target = document.querySelector(targetId);
      if (!target) return;
      target.addEventListener('show.bs.collapse', () => {
        btn.querySelector('.nav-caret')?.classList.replace('bi-caret-right-fill', 'bi-caret-down-fill');
      });
      target.addEventListener('hide.bs.collapse', () => {
        btn.querySelector('.nav-caret')?.classList.replace('bi-caret-down-fill', 'bi-caret-right-fill');
      });
    });
  }

  /**
   * Highlights the sidebar item that matches the current route.
   */
  function updateSidebarActive(route) {
    document.querySelectorAll('.nav-item, .nav-suite-link, .nav-run-link').forEach((el) => {
      el.classList.remove('active');
    });

    if (route.view === 'dashboard') {
      document.querySelector('[data-route="dashboard"]')?.classList.add('active');
    } else if (route.view === 'process') {
      document.querySelectorAll(`[data-process-id="${CSS.escape(route.processId)}"]`)
        .forEach((el) => el.classList.add('active'));
    } else if (route.view === 'suite') {
      document.querySelectorAll(`[data-suite-id="${CSS.escape(route.suiteId)}"][data-route="suite"]`)
        .forEach((el) => el.classList.add('active'));
    } else if (route.view === 'run') {
      document.querySelectorAll(`[data-run-name="${CSS.escape(route.runName)}"]`)
        .forEach((el) => el.classList.add('active'));
    }
  }

  // ── Views ─────────────────────────────────────────────────────────────────────

  /** Active bpmn-js viewer instance (destroyed when navigating away). */
  let bpmnViewer = null;

  function destroyBpmnViewer() {
    if (bpmnViewer) {
      try {
        bpmnViewer.destroy();
      } catch (_) {
        // Ignore errors during destruction
      }
      bpmnViewer = null;
    }
    const canvas = document.getElementById('bpmn-canvas');
    if (canvas) canvas.innerHTML = '';
  }

  // ── Dashboard view ────────────────────────────────────────────────────────────

  function renderDashboard() {
    const totalSuites = suites.length;
    const totalProcesses = globalCoverages.length;
    const totalRuns = suites.reduce((sum, s) => sum + (s.runs || []).length, 0);
    const avgCoverage =
      totalProcesses > 0
        ? globalCoverages.reduce((sum, c) => sum + c.coverage, 0) / totalProcesses
        : 0;

    const sorted = [...globalCoverages].sort((a, b) => b.coverage - a.coverage);

    let html = `
      <h2 class="view-title">
        <i class="bi bi-house-fill me-2" aria-hidden="true"></i>Coverage Dashboard
      </h2>

      <!-- Summary cards -->
      <div class="row g-3 mb-4">
        ${statCard(totalSuites, 'Test Suites', 'bi-folder-fill')}
        ${statCard(totalRuns, 'Test Cases', 'bi-file-earmark-code-fill')}
        ${statCard(totalProcesses, 'Processes', 'bi-diagram-3-fill')}
        ${statCard(toPercent(avgCoverage), 'Avg. Coverage', 'bi-bar-chart-fill', coverageClass(avgCoverage))}
      </div>

      <!-- Process overview table -->
      <h3 class="section-title">Process Coverage Overview</h3>`;

    if (sorted.length === 0) {
      html += '<p class="text-muted">No process coverage data available.</p>';
    } else {
      html += '<div class="table-responsive"><table class="table table-hover align-middle">';
      html += `<thead><tr>
        <th>Process</th>
        <th style="width:200px">Coverage</th>
        <th style="width:100px">Ratio</th>
        <th style="width:120px">Elements</th>
      </tr></thead><tbody>`;

      for (const cov of sorted) {
        const pid = encodeURIComponent(cov.processDefinitionId);
        const model = (data.suites || []).flatMap(s => s.models || []).find(m => m.processDefinitionId === cov.processDefinitionId);
        const total = model ? model.totalElementCount : '?';
        const completed = (cov.completedElements || []).length;
        html += `
          <tr class="clickable-row" onclick="navigate('/process/${pid}')">
            <td>
              <i class="bi bi-diagram-3-fill me-2 text-primary" aria-hidden="true"></i>
              <strong>${escapeHtml(cov.processDefinitionId)}</strong>
            </td>
            <td>${progressBarHtml(cov.coverage)}</td>
            <td>${badgeHtml(cov.coverage)}</td>
            <td><span class="text-muted">${completed} / ${total}</span></td>
          </tr>`;
      }

      html += '</tbody></table></div>';
    }

    // Test suites overview
    html += '<h3 class="section-title mt-4">Test Suites</h3>';
    if (suites.length === 0) {
      html += '<p class="text-muted">No test suites available.</p>';
    } else {
      html += '<div class="list-group">';
      for (const suite of suites) {
        const sid = encodeURIComponent(suite.id);
        const suiteCoverages = suite.coverages || [];
        const suiteAvg =
          suiteCoverages.length > 0
            ? suiteCoverages.reduce((s, c) => s + c.coverage, 0) / suiteCoverages.length
            : 0;
        html += `
          <a href="#/suite/${sid}"
             class="list-group-item list-group-item-action d-flex justify-content-between align-items-center">
            <div>
              <i class="bi bi-folder-fill me-2 text-warning" aria-hidden="true"></i>
              <strong>${escapeHtml(suite.name)}</strong>
              <small class="text-muted ms-2">${(suite.runs || []).length} test case(s)</small>
            </div>
            <div class="d-flex align-items-center gap-2">
              ${progressBarHtml(suiteAvg)}
              ${badgeHtml(suiteAvg)}
            </div>
          </a>`;
      }
      html += '</div>';
    }

    document.getElementById('content').innerHTML = html;

    // Make navigate() accessible for onclick attributes in this view
    window.navigate = navigate;
  }

  function statCard(value, label, icon, extraClass) {
    const cls = extraClass ? `coverage-stat-value ${extraClass}` : 'coverage-stat-value';
    return `
      <div class="col-sm-6 col-lg-3">
        <div class="card stat-card h-100">
          <div class="card-body text-center">
            <div class="${cls}">${value}</div>
            <div class="stat-label">
              <i class="bi ${icon} me-1" aria-hidden="true"></i>${label}
            </div>
          </div>
        </div>
      </div>`;
  }

  // ── Process view ──────────────────────────────────────────────────────────────

  async function renderProcess(processId) {
    const cov = findGlobalCoverage(processId);
    const xml = definitions[processId];

    let html = `
      <h2 class="view-title">
        <i class="bi bi-diagram-3-fill me-2" aria-hidden="true"></i>
        ${escapeHtml(processId)}
      </h2>`;

    if (cov) {
      const completed = (cov.completedElements || []).length;
      const flows = (cov.takenSequenceFlows || []).length;
      html += `
        <div class="row g-3 mb-4">
          ${statCard(toPercent(cov.coverage), 'Coverage', 'bi-bar-chart-fill', coverageClass(cov.coverage))}
          ${statCard(completed, 'Completed Elements', 'bi-check-circle-fill')}
          ${statCard(flows, 'Taken Flows', 'bi-arrow-right-circle-fill')}
        </div>`;
    }

    html += `
      <h3 class="section-title">BPMN Diagram</h3>
      <div id="bpmn-canvas" class="bpmn-canvas"></div>`;

    if (cov) {
      html += `
        <div class="mt-3">
          <h3 class="section-title">Coverage Details</h3>
          <div class="row">
            <div class="col-md-6">
              <h5>Completed Elements <span class="badge text-bg-secondary">${(cov.completedElements || []).length}</span></h5>
              ${elementList(cov.completedElements)}
            </div>
            <div class="col-md-6">
              <h5>Taken Sequence Flows <span class="badge text-bg-secondary">${(cov.takenSequenceFlows || []).length}</span></h5>
              ${elementList(cov.takenSequenceFlows)}
            </div>
          </div>
        </div>`;
    }

    // Suite coverage for this process
    const suitesForProcess = suites.filter((s) =>
      (s.coverages || []).some((c) => c.processDefinitionId === processId)
    );
    if (suitesForProcess.length > 0) {
      html += '<h3 class="section-title mt-4">Test Suite Coverage</h3>';
      html += '<div class="list-group">';
      for (const suite of suitesForProcess) {
        const suiteCov = (suite.coverages || []).find(
          (c) => c.processDefinitionId === processId
        );
        const sid = encodeURIComponent(suite.id);
        html += `
          <a href="#/suite/${sid}" class="list-group-item list-group-item-action d-flex justify-content-between align-items-center">
            <span>
              <i class="bi bi-folder-fill me-2 text-warning" aria-hidden="true"></i>
              ${escapeHtml(suite.name)}
            </span>
            <div class="d-flex align-items-center gap-2">
              ${suiteCov ? progressBarHtml(suiteCov.coverage) : ''}
              ${suiteCov ? badgeHtml(suiteCov.coverage) : ''}
            </div>
          </a>`;
      }
      html += '</div>';
    }

    document.getElementById('content').innerHTML = html;

    // Render BPMN diagram
    if (xml) {
      await renderBpmnDiagram(xml, cov);
    } else {
      document.getElementById('bpmn-canvas').innerHTML =
        '<p class="text-muted p-3">No BPMN definition available for this process.</p>';
    }
  }

  function elementList(items) {
    if (!items || items.length === 0) {
      return '<p class="text-muted">None</p>';
    }
    return `
      <ul class="list-group list-group-flush element-list">
        ${items
          .map(
            (id) =>
              `<li class="list-group-item py-1 px-2">
                 <i class="bi bi-check2 text-success me-2" aria-hidden="true"></i>
                 <code>${escapeHtml(id)}</code>
               </li>`
          )
          .join('')}
      </ul>`;
  }

  /**
   * Renders the BPMN XML into the canvas element and highlights covered elements.
   * @param {string} xml BPMN XML string
   * @param {object|undefined} cov Coverage data object
   */
  async function renderBpmnDiagram(xml, cov) {
    destroyBpmnViewer();

    const container = document.getElementById('bpmn-canvas');
    if (!container) return;

    if (typeof window.BpmnJS === 'undefined') {
      container.innerHTML = '<p class="text-danger p-3">bpmn-js library not loaded.</p>';
      return;
    }

    bpmnViewer = new window.BpmnJS({ container });

    try {
      await bpmnViewer.importXML(xml);
      const canvas = bpmnViewer.get('canvas');
      canvas.zoom('fit-viewport');

      if (cov) {
        applyDiagramCoverage(bpmnViewer, cov);
      }
    } catch (err) {
      console.error('Could not import BPMN diagram', err);
      container.innerHTML =
        `<p class="text-danger p-3">Failed to render BPMN diagram: ${escapeHtml(String(err))}</p>`;
      bpmnViewer = null;
    }
  }

  /**
   * Applies coverage highlighting to the bpmn-js viewer.
   * @param {object} viewer bpmn-js viewer instance
   * @param {object} cov Coverage data
   */
  function applyDiagramCoverage(viewer, cov) {
    const canvas = viewer.get('canvas');
    const elementRegistry = viewer.get('elementRegistry');
    const graphicsFactory = viewer.get('graphicsFactory');

    // Highlight completed elements (tasks, events, gateways)
    for (const elementId of cov.completedElements || []) {
      try {
        canvas.addMarker(elementId, 'coverage-completed');
      } catch (_) {
        // Element may not exist in diagram – ignore
      }
    }

    // Highlight taken sequence flows with Camunda Blue
    for (const flowId of cov.takenSequenceFlows || []) {
      try {
        const flow = elementRegistry.get(flowId);
        if (!flow) continue;
        const gfx = elementRegistry.getGraphics(flow);
        const di = flow.businessObject.di;
        di.set('stroke', COLORS.blue);
        di.set('fill', COLORS.blue);
        graphicsFactory.update('connection', flow, gfx);
      } catch (_) {
        // Ignore errors for individual elements
      }
    }
  }

  // ── Suite view ────────────────────────────────────────────────────────────────

  function renderSuite(suiteId) {
    const suite = findSuite(suiteId);
    if (!suite) {
      document.getElementById('content').innerHTML =
        `<div class="alert alert-warning">Suite not found: ${escapeHtml(suiteId)}</div>`;
      return;
    }

    const suiteCoverages = suite.coverages || [];
    const runs = suite.runs || [];
    const avgCoverage =
      suiteCoverages.length > 0
        ? suiteCoverages.reduce((s, c) => s + c.coverage, 0) / suiteCoverages.length
        : 0;

    let html = `
      <h2 class="view-title">
        <i class="bi bi-folder-fill me-2 text-warning" aria-hidden="true"></i>
        ${escapeHtml(suite.name)}
      </h2>
      <div class="row g-3 mb-4">
        ${statCard(runs.length, 'Test Cases', 'bi-file-earmark-code-fill')}
        ${statCard(suiteCoverages.length, 'Processes', 'bi-diagram-3-fill')}
        ${statCard(toPercent(avgCoverage), 'Avg. Coverage', 'bi-bar-chart-fill', coverageClass(avgCoverage))}
      </div>

      <h3 class="section-title">Process Coverage</h3>`;

    if (suiteCoverages.length === 0) {
      html += '<p class="text-muted">No coverage data available for this suite.</p>';
    } else {
      html += '<div class="table-responsive"><table class="table table-hover align-middle">';
      html += `<thead><tr>
        <th>Process</th>
        <th style="width:200px">Coverage</th>
        <th style="width:100px">Ratio</th>
      </tr></thead><tbody>`;

      const sorted = [...suiteCoverages].sort((a, b) => b.coverage - a.coverage);
      for (const cov of sorted) {
        const pid = encodeURIComponent(cov.processDefinitionId);
        html += `
          <tr class="clickable-row" onclick="navigate('/process/${pid}')">
            <td>
              <i class="bi bi-diagram-3-fill me-2 text-primary" aria-hidden="true"></i>
              ${escapeHtml(cov.processDefinitionId)}
            </td>
            <td>${progressBarHtml(cov.coverage)}</td>
            <td>${badgeHtml(cov.coverage)}</td>
          </tr>`;
      }
      html += '</tbody></table></div>';
    }

    html += '<h3 class="section-title mt-4">Test Cases</h3>';
    if (runs.length === 0) {
      html += '<p class="text-muted">No test cases recorded for this suite.</p>';
    } else {
      html += '<div class="list-group">';
      const sid = encodeURIComponent(suite.id);
      for (const run of runs) {
        const rn = encodeURIComponent(run.name);
        const runCoverages = run.coverages || [];
        const runAvg =
          runCoverages.length > 0
            ? runCoverages.reduce((s, c) => s + c.coverage, 0) / runCoverages.length
            : 0;
        html += `
          <a href="#/suite/${sid}/run/${rn}"
             class="list-group-item list-group-item-action d-flex justify-content-between align-items-center">
            <div>
              <i class="bi bi-file-earmark-code-fill me-2 text-info" aria-hidden="true"></i>
              <strong>${escapeHtml(run.name)}</strong>
              <small class="text-muted ms-2">${runCoverages.length} process(es)</small>
            </div>
            <div class="d-flex align-items-center gap-2">
              ${progressBarHtml(runAvg)}
              ${badgeHtml(runAvg)}
            </div>
          </a>`;
      }
      html += '</div>';
    }

    document.getElementById('content').innerHTML = html;
    window.navigate = navigate;
  }

  // ── Run (test-case) view ───────────────────────────────────────────────────────

  function renderRun(suiteId, runName) {
    const suite = findSuite(suiteId);
    if (!suite) {
      document.getElementById('content').innerHTML =
        `<div class="alert alert-warning">Suite not found: ${escapeHtml(suiteId)}</div>`;
      return;
    }

    const run = (suite.runs || []).find((r) => r.name === runName);
    if (!run) {
      document.getElementById('content').innerHTML =
        `<div class="alert alert-warning">Test case not found: ${escapeHtml(runName)}</div>`;
      return;
    }

    const runCoverages = run.coverages || [];
    const avgCoverage =
      runCoverages.length > 0
        ? runCoverages.reduce((s, c) => s + c.coverage, 0) / runCoverages.length
        : 0;

    const sid = encodeURIComponent(suite.id);

    let html = `
      <nav aria-label="breadcrumb" class="mb-3">
        <ol class="breadcrumb">
          <li class="breadcrumb-item">
            <a href="#/suite/${sid}">${escapeHtml(suite.name)}</a>
          </li>
          <li class="breadcrumb-item active" aria-current="page">${escapeHtml(run.name)}</li>
        </ol>
      </nav>

      <h2 class="view-title">
        <i class="bi bi-file-earmark-code-fill me-2 text-info" aria-hidden="true"></i>
        ${escapeHtml(run.name)}
      </h2>

      <div class="row g-3 mb-4">
        ${statCard(runCoverages.length, 'Processes', 'bi-diagram-3-fill')}
        ${statCard(toPercent(avgCoverage), 'Avg. Coverage', 'bi-bar-chart-fill', coverageClass(avgCoverage))}
      </div>

      <h3 class="section-title">Processes Covered</h3>`;

    if (runCoverages.length === 0) {
      html += '<p class="text-muted">No coverage data recorded for this test case.</p>';
    } else {
      html += '<div class="table-responsive"><table class="table table-hover align-middle">';
      html += `<thead><tr>
        <th>Process</th>
        <th style="width:200px">Coverage</th>
        <th style="width:100px">Ratio</th>
        <th style="width:120px">Elements</th>
      </tr></thead><tbody>`;

      const sorted = [...runCoverages].sort((a, b) => b.coverage - a.coverage);
      for (const cov of sorted) {
        const pid = encodeURIComponent(cov.processDefinitionId);
        const completed = (cov.completedElements || []).length;
        const flows = (cov.takenSequenceFlows || []).length;
        html += `
          <tr class="clickable-row" onclick="navigate('/process/${pid}')">
            <td>
              <i class="bi bi-diagram-3-fill me-2 text-primary" aria-hidden="true"></i>
              ${escapeHtml(cov.processDefinitionId)}
            </td>
            <td>${progressBarHtml(cov.coverage)}</td>
            <td>${badgeHtml(cov.coverage)}</td>
            <td><span class="text-muted">${completed} el. / ${flows} fl.</span></td>
          </tr>`;
      }
      html += '</tbody></table></div>';
    }

    document.getElementById('content').innerHTML = html;
    window.navigate = navigate;
  }

  // ── Router / main render loop ─────────────────────────────────────────────────

  async function render() {
    destroyBpmnViewer();

    const route = parseRoute();
    updateSidebarActive(route);

    switch (route.view) {
      case 'dashboard':
        renderDashboard();
        break;
      case 'process':
        await renderProcess(route.processId);
        break;
      case 'suite':
        renderSuite(route.suiteId);
        break;
      case 'run':
        renderRun(route.suiteId, route.runName);
        break;
      default:
        renderDashboard();
    }
  }

  // ── Initialise ────────────────────────────────────────────────────────────────

  window.addEventListener('hashchange', render);

  // Expose navigate globally so onclick attributes can use it
  window.navigate = navigate;

  // Initial render
  renderSidebar();
  render();
})();
